import React, { useState, useEffect, useMemo, useCallback, useRef } from 'react';
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';

interface Props {
  location: string;
  current: {
    temp: number;
    condition: string;
    humidity: number;
    windSpeed: number;
  };
  forecast: Array<{
    day: string;
    condition: string;
    high: number;
    low: number;
  }>;
}

function useComponent(props: Props) {
  return {
    ...props,
    getIcon: (condition: string) => {
      switch (condition.toLowerCase()) {
        case 'sunny': return '☀️';
        case 'cloudy': return '☁️';
        case 'rainy': return '🌧️';
        default: return '🌤️';
      }
    }
  };
}

export default function Component(props: Props) {
  const state = useComponent(props);

  return (
    <Card shadow="md" padding={24} radius="lg">
      <Stack gap={16}>
        <Heading level={2}>{state.location}</Heading>
        <Stack direction="horizontal" align="center" gap={16}>
          <Heading level={1} color="var(--ggui-color-primary-600, #0284c7)">{state.current.temp}°</Heading>
          <Text variant="bodyLarge">{state.getIcon(state.current.condition)} {state.current.condition}</Text>
        </Stack>
        <Row gap={16}>
          <Badge variant="secondary">Humidity: {state.current.humidity}%</Badge>
          <Badge variant="secondary">Wind: {state.current.windSpeed} km/h</Badge>
        </Row>
        <Divider />
        <Stack direction="horizontal" justify="between">
          {state.forecast.map((f, i) => (
            <Stack key={i} align="center" gap={4}>
              <Text variant="caption">{f.day}</Text>
              <Text>{state.getIcon(f.condition)}</Text>
              <Text variant="label">{f.high}° / {f.low}°</Text>
            </Stack>
          ))}
        </Stack>
      </Stack>
    </Card>
  );
}

import React, { useState, useEffect, useMemo, useCallback, useRef } from 'react';
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';

interface Props {
  elements: {
    atomicNumber: number;
    symbol: string;
    name: string;
    atomicWeight: number;
    category: string;
    gridRow: number;
    gridColumn: number;
  }[];
}

function useComponent(props: Props) {
  const [query, setQuery] = useState('');
  const [selected, setSelected] = useState<Props['elements'][0] | null>(null);

  const filtered = useMemo(() => {
    if (!query) return props.elements;
    const q = query.toLowerCase();
    return props.elements.filter(
      (el) => el.name.toLowerCase().includes(q) || el.symbol.toLowerCase().includes(q)
    );
  }, [props.elements, query]);

  const categories = useMemo(() => Array.from(new Set(props.elements.map((e) => e.category))), [props.elements]);

  return { query, setQuery, selected, setSelected, filtered, categories };
}

export default function Component(props: Props) {
  const { query, setQuery, selected, setSelected, filtered, categories } = useComponent(props);

  const getColor = (cat: string) => {
    const colors: Record<string, string> = {
      'noble gas': 'var(--ggui-color-info-200)',
      'halogen': 'var(--ggui-color-warning-200)',
      'alkali metal': 'var(--ggui-color-primary-200)',
      'alkaline earth metal': 'var(--ggui-color-primary-100)',
    };
    return colors[cat] || 'var(--ggui-color-surfaceVariant)';
  };

  return (
    <Container maxWidth="3xl" padding={24}>
      <Stack gap={24}>
        <Heading level={1}>Periodic Table</Heading>
        <Input label="Search element" value={query} onChange={setQuery} placeholder="Name or Symbol..." />

        <Box padding={16} background="var(--ggui-color-surfaceVariant)" borderRadius="md">
          <Stack direction="horizontal" gap={16} wrap>
            {categories.map((cat) => (
              <Stack key={cat} direction="horizontal" gap={8} align="center">
                <Box padding={8} background={getColor(cat)} borderRadius="sm" />
                <Text variant="caption">{cat}</Text>
              </Stack>
            ))}
          </Stack>
        </Box>

        <div style={{ display: 'grid', gridTemplateColumns: 'repeat(18, 1fr)', gap: 'var(--ggui-spacing-1)' }}>
          {filtered.map((el) => (
            <div
              key={el.symbol}
              style={{ 
                padding: 'var(--ggui-spacing-2)',
                backgroundColor: getColor(el.category),
                borderRadius: 'var(--ggui-shape-radius-sm)',
                gridRow: el.gridRow, 
                gridColumn: el.gridColumn, 
                cursor: 'pointer',
                border: selected?.symbol === el.symbol ? '2px solid var(--ggui-color-primary-600)' : 'none'
              }}
              onClick={() => setSelected(el)}
            >
              <Text variant="caption" size="xs">{el.atomicNumber}</Text>
              <Heading level={4} align="center">{el.symbol}</Heading>
            </div>
          ))}
        </div>

        {selected && (
          <Card padding={24} shadow="md">
            <Stack gap={8}>
              <Heading level={2}>{selected.name} ({selected.symbol})</Heading>
              <Divider />
              <Stack direction="horizontal" gap={16}>
                <Box>
                  <Text variant="label">Atomic Number</Text>
                  <Text>{selected.atomicNumber}</Text>
                </Box>
                <Box>
                  <Text variant="label">Atomic Weight</Text>
                  <Text>{selected.atomicWeight}</Text>
                </Box>
                <Box>
                  <Text variant="label">Category</Text>
                  <Badge variant="secondary">{selected.category}</Badge>
                </Box>
              </Stack>
            </Stack>
          </Card>
        )}
      </Stack>
    </Container>
  );
}

import React, { useState, useEffect, useMemo, useCallback, useRef } from 'react';
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';

interface Props {
  properties: unknown;
}

// Action handlers (call these from event handlers):
//   props.actions: {"complete":{"label":"Complete Setup","description":"Called with all profile data when user completes onboarding","example":{"name":"Jane","email":"jane@example.com","avatar":"🧑‍💻","role":"Developer","emailNotifications":true,"theme":"dark"}}}
function useComponent(props: Props) {
  const [step, setStep] = useState(1);
  const [formData, setFormData] = useState({
    name: '',
    email: '',
    avatar: '🧑‍💻',
    role: 'Developer',
    emailNotifications: true,
    theme: 'light'
  });

  const update = (key: string, value: any) => setFormData(prev => ({ ...prev, [key]: value }));

  const isValid = useMemo(() => {
    if (step === 1) return formData.name.length > 0 && /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(formData.email);
    return true;
  }, [step, formData]);

  const next = () => setStep(s => Math.min(s + 1, 3));
  const back = () => setStep(s => Math.max(s - 1, 1));

  return { step, formData, update, isValid, next, back };
}

export default function Component(props: Props) {
  const { step, formData, update, isValid, next, back } = useComponent(props);

  return (
    <Container maxWidth="md" padding={24}>
      <Stack gap={24}>
        <Stack gap={8}>
          <Heading level={2}>Onboarding ({step}/3)</Heading>
          <Progress value={step === 1 ? 33 : step === 2 ? 66 : 100} />
        </Stack>

        {step === 1 && (
          <Card padding={24}>
            <Stack gap={16}>
              <Input label="Name" value={formData.name} onChange={(v) => update('name', v)} required />
              <Input label="Email" type="email" value={formData.email} onChange={(v) => update('email', v)} required />
              <Text variant="label">Choose Avatar</Text>
              <RadioGroup value={formData.avatar} onChange={(v) => update('avatar', v)} direction="horizontal" options={['🧑‍💻', '🎨', '💼', '🚀'].map(e => ({ value: e, label: e }))} />
            </Stack>
          </Card>
        )}

        {step === 2 && (
          <Card padding={24}>
            <Stack gap={16}>
              <Select label="Role" value={formData.role} onChange={(v) => update('role', v)} options={['Developer', 'Designer', 'Manager', 'Other'].map(r => ({ value: r, label: r }))} />
              <Toggle label="Email Notifications" checked={formData.emailNotifications} onChange={(v) => update('emailNotifications', v)} />
              <Toggle label="Dark Theme" checked={formData.theme === 'dark'} onChange={(v) => update('theme', v ? 'dark' : 'light')} />
            </Stack>
          </Card>
        )}

        {step === 3 && (
          <Card padding={24}>
            <Stack gap={8}>
              <Heading level={4}>Review</Heading>
              <Text>Name: {formData.name}</Text>
              <Text>Email: {formData.email}</Text>
              <Text>Role: {formData.role}</Text>
            </Stack>
          </Card>
        )}

        <Row justify="between">
          <Button variant="ghost" onClick={back} disabled={step === 1}>Back</Button>
          {step < 3 ? (
            <Button onClick={next} disabled={!isValid}>Next</Button>
          ) : (
            <Button variant="primary" onClick={() => (props as any).actions?.complete?.(formData)}>Complete Setup</Button>
          )}
        </Row>
      </Stack>
    </Container>
  );
}
